const text1 = ''被告应当承担全部责任'';
const text2 = ''被告不应当承担任何责任'';

function extractKeywords\(text\) {
  const stopWords = new Set\([''的'', ''了'', ''是'', ''在'', ''和'', ''有'', ''我'', ''你'', ''他'', ''她'', ''它'', ''我们'', ''你们'', ''他们'', ''这'', ''那'', ''这个'', ''那个'', ''一个'']\);
  const words = text
    .replace\(/[，。！？；：""''''（）@#$%^&*\\-_+=\\[\\]{}|\\/<>~\\`]/g, '' ''\)
    .split\(/\\s+/\)
    .filter\(word => word.length > 1 && !stopWords.has\(word\)\);
  return [...new Set\(words\)];
}

const k1 = extractKeywords\(text1\);
const k2 = extractKeywords\(text2\);
console.log\(''text1:'', text1\);
console.log\(''keywords1:'', k1\);
console.log\(''text2:'', text2\);
console.log\(''keywords2:'', k2\);
console.log\(''common:'', k1.filter\(k => k2.includes\(k\)\)\);
console.log\(''text1 includes 应当:'', text1.includes\(''应当''\)\);
console.log\(''text2 includes 不应当:'', text2.includes\(''不应当''\)\);
")

